import React, { useEffect, useState } from "react";
import { MapContainer, TileLayer, Marker, Popup } from "react-leaflet";
import L from "leaflet";
import "leaflet/dist/leaflet.css";
import BusTrendChart from "./BusTrendChart";

// Function to create colored circle icons
const createCircleIcon = (color) => {
  return L.divIcon({
    className: "custom-div-icon",
    html: `<div style="background-color:${color}; width:15px; height:15px; border-radius:50%; border: 2px solid white;"></div>`,
    iconSize: [15, 15],
    iconAnchor: [7, 7]
  });
};

const MapComponent = () => {
  const [buses, setBuses] = useState([]);
  const [showChart, setShowChart] = useState(false);

  useEffect(() => {
    const fetchBuses = async () => {
      try {
        const response = await fetch("http://localhost:8000/buses");
        const data = await response.json();
        setBuses(data);
      } catch (error) {
        console.error("Error fetching bus data:", error);
      }
    };

    fetchBuses();
    const interval = setInterval(fetchBuses, 120000); // 2 minutes
    return () => clearInterval(interval);
  }, []);

  const normalCount = buses.filter(b => b.status === "normal").length;
  const ghostCount = buses.filter(b => b.status === "ghost").length;
  const anomalyCount = buses.filter(b => b.status === "anomaly").length;

  return (
    <div style={{ position: "relative" }}>
      <MapContainer center={[40.7128, -74.0060]} zoom={11} style={{ height: "100vh", width: "100vw" }}>
        {/* White map tiles */}
        <TileLayer
          url="https://tiles.stadiamaps.com/tiles/alidade_smooth/{z}/{x}/{y}{r}.png"
          attribution='&copy; <a href="https://stadiamaps.com/">Stadia Maps</a>'
        />

        {buses.map(bus => {
          let color = "green";
          if (bus.status === "ghost") color = "red";
          else if (bus.status === "anomaly") color = "orange";

          return (
            <Marker
              key={bus.id + Math.random()} // ensures unique keys
              position={[bus.lat, bus.lon]}
              icon={createCircleIcon(color)}
            >
              <Popup>{bus.status.toUpperCase()}</Popup>
            </Marker>
          );
        })}
      </MapContainer>

      {/* Bottom Left Stats */}
      <div style={{ position: "absolute", bottom: 20, left: 20, backgroundColor: "white", padding: "10px", borderRadius: "8px" }}>
        <p>Normal: {normalCount} | Ghost: {ghostCount} | Anomaly: {anomalyCount}</p>
        <button onClick={() => setShowChart(!showChart)}>{showChart ? "Hide Chart" : "Show Chart"}</button>
      </div>

      {showChart && <BusTrendChart buses={buses} />}
    </div>
  );
};

export default MapComponent;
